'use client'

import { useState } from 'react'
import { Filter, SlidersHorizontal } from 'lucide-react'
import '../../styles/Matchfilters.css'

export default function MatchFilters() {
  const [activeSport, setActiveSport] = useState('All')
  
  // Static list for layout - we can make this dynamic later
  const sports = [
    'All', 'NFL', 'NBA', 'Soccer', 'Cricket', 'F1', 'MMA', 'Tennis', 'Rugby'
  ]

  return (
    <div className="filters-section">
      <div className="filters-bar">
        
        {/* SCROLLABLE SPORTS */}
        <div className="sports-scroll-area">
          {sports.map((sport) => (
            <button
              key={sport}
              className={`filter-pill ${activeSport === sport ? 'active' : ''}`}
              onClick={() => setActiveSport(sport)}
            >
              {sport}
            </button>
          ))}
        </div>

        {/* DIVIDER */}
        <div className="separator"></div>

        {/* SOURCE FILTER BUTTON */}
        <button className="source-filter-btn">
          <SlidersHorizontal size={14} />
          <span>Filter Sources</span>
          {/* <span className="source-count">3</span> */}
        </button>

      </div>
    </div>
  )
}